mapper.select:
SELECT T.JOB_NM ,T.JOB_DATE ,T.JOB_END_DATE ,T.JOB_RLT ,T.JOB_RLT_MSG FROM (SELECT GETCODENAME(#{ses.gateCd}, 'M177', BL.JOB_ID, #{ses.langCd}) as JOB_NM , (BL.JOB_DATE, 'YYYY-MM-DD HH24:MI') as JOB_DATE , (BL.JOB_END_DATE, 'YYYY-MM-DD HH24:MI') as JOB_END_DATE , BL.JOB_RLT , BL.JOB_RLT_MSG --, (CASE BL.JOB_RLT WHEN 'E' THEN BL.JOB_RLT_MSG ELSE NULL END) as JOB_RLT_MSG FROM STOCBLOG BL WHERE BL.JOB_TYPE = 'Batch'
AND BL.JOB_DATE >= (#{JOB_DATE_FROM}) AND BL.JOB_DATE <= (#{JOB_DATE_TO})
AND BL.JOB_ID = #{JOB_NM}
AND BL.JOB_RLT = #{JOB_RLT}
) T WHERE 1 = 1 ORDER BY T.JOB_DATE DESC

mapper.insert:
INSERT INTO STOCBLOG
		(
		  JOB_SQ
		 ,JOB_DATE
		 ,JOB_TYPE
		 ,JOB_ID
		 ,JOB_KEY
		 ,JOB_RLT
		 ,JOB_RLT_CD
		 ,JOB_RLT_MSG
		 ,JOB_END_DATE
		)
VALUES
		(
		  SEQ_STOCBLOG.NEXTVAL
		 ,(#{JOB_DATE}, 'YYYYMMDDHH24MISS')
		 ,#{JOB_TYPE}
		 ,#{JOB_ID}
		 ,#{JOB_KEY}
		 ,#{JOB_RLT}
		 ,#{JOB_RLT_CD}
		 ,#{JOB_RLT_MSG}
		 ,(#{JOB_END_DATE}, 'YYYYMMDDHH24MISS')
		)

mapper.select:
SELECT T.JOB_NM ,T.JOB_NUM ,T.JOB_DATE ,T.JOB_END_DATE ,T.JOB_RLT ,T.JOB_RLT_MSG ,T.JOB_KEY FROM (SELECT GETCODENAME(#{ses.gateCd}, 'M177', BL.JOB_ID, #{ses.langCd}) as JOB_NM , BL.JOB_NUM , (BL.JOB_DATE, 'YYYY-MM-DD HH24:MI') as JOB_DATE , (BL.JOB_END_DATE, 'YYYY-MM-DD HH24:MI') as JOB_END_DATE , BL.JOB_RLT , BL.JOB_RLT_MSG , GETCODENAME(#{ses.gateCd}, 'NH0048', BL.JOB_KEY, #{ses.langCd}) as JOB_KEY FROM STOCBLOG BL WHERE BL.JOB_TYPE = 'Guar'
AND BL.JOB_DATE >= (#{JOB_DATE_FROM}) AND BL.JOB_DATE <= (#{JOB_DATE_TO})
AND BL.JOB_ID = #{JOB_ID}
AND BL.JOB_RLT = #{JOB_RLT}
AND BL.JOB_KEY = #{JOB_KEY}
) T WHERE 1 = 1 ORDER BY T.JOB_DATE DESC
